def backfill_wiki_locations(apps, schema_editor):
    """Ensure every wiki has a Location before the OneToOne becomes required."""
    Wiki = apps.get_model("dashboard", "Wiki")
    Location = apps.get_model("dashboard", "Location")
    Pin = apps.get_model("dashboard", "Pin")
    Campus = apps.get_model("dashboard", "Campus")

    updated: list[object] = []
    for wiki in Wiki.objects.filter(location__isnull=True).iterator():
        campus = Campus.objects.filter(wiki=wiki, location__isnull=False).order_by("pk").first()
        if campus is not None:
            wiki.location_id = campus.location_id
            updated.append(wiki)
            continue

        pin = Pin.objects.filter(parent_wiki=wiki, location__isnull=False).order_by("pk").first()
        if pin is not None:
            wiki.location_id = pin.location_id
            updated.append(wiki)
            continue

        pin = Pin.objects.filter(wiki=wiki, location__isnull=False).order_by("pk").first()
        if pin is not None:
            wiki.location_id = pin.location_id
            updated.append(wiki)
            continue

        # Orphan wiki with no spatial anchor: create a dedicated Location row.
        # Prefer a non-zero pin coordinate if any child pin exists.
        anchor = Pin.objects.filter(parent_wiki=wiki).order_by("pk").first()
        if anchor is None:
            anchor = Pin.objects.filter(wiki=wiki).order_by("pk").first()
        if anchor is not None:
            latitude = _quantize_coord(anchor.latitude)
            longitude = _quantize_coord(anchor.longitude)
        else:
            latitude = Decimal(0)
            longitude = Decimal(0)

        location = _get_or_create_location(
            Location,
            latitude,
            longitude,
            official_name=wiki.name or "Unnamed Location",
        )
        wiki.location_id = location.pk
        updated.append(wiki)

    if updated:
        Wiki.objects.bulk_update(updated, ["location"], batch_size=500)


def dedupe_wikis_per_location(apps, schema_editor):
    """OneToOne requires at most one wiki per Location."""
    Wiki = apps.get_model("dashboard", "Wiki")
    Location = apps.get_model("dashboard", "Location")

    seen_location_ids: set[int] = set()
    for wiki in Wiki.objects.filter(location__isnull=False).order_by("location_id", "pk").iterator():
        if wiki.location_id in seen_location_ids:
            source = Location.objects.get(pk=wiki.location_id)
            latitude = _quantize_coord(source.latitude)
            longitude = _quantize_coord(source.longitude)
            while Location.objects.filter(latitude=latitude, longitude=longitude).exists():
                longitude += COORD_STEP
            new_location = Location.objects.create(
                official_name=source.official_name or wiki.name,
                latitude=latitude,
                longitude=longitude,
                point=_point_for(latitude, longitude),
            )
            wiki.location_id = new_location.pk
            wiki.save(update_fields=["location"])
        else:
            seen_location_ids.add(wiki.location_id)


def backfill_pin_wiki(apps, schema_editor):
    """Link public pins to their community wiki when one exists for the Location."""
    Pin = apps.get_model("dashboard", "Pin")
    Wiki = apps.get_model("dashboard", "Wiki")

    updated: list[object] = []
    for pin in Pin.objects.filter(wiki__isnull=True, is_private=False, location__isnull=False).iterator():
        wiki = Wiki.objects.filter(location_id=pin.location_id).order_by("pk").first()
        if wiki is None:
            continue
        pin.wiki_id = wiki.pk
        updated.append(pin)

    if updated:
        Pin.objects.bulk_update(updated, ["wiki"], batch_size=500)



